const msg = $('Message Trigger').first().json.message;
const chatId = msg.chat.id;
const messageId = msg.message_id;

const staticData = $getWorkflowStaticData('global');
if (!staticData.processedIds) staticData.processedIds = [];
const dedupKey = msg.voice?.file_unique_id || msg.audio?.file_unique_id || msg.photo?.[0]?.file_unique_id || String(messageId);
if (staticData.processedIds.includes(dedupKey)) { return []; }
staticData.processedIds.push(dedupKey);
if (staticData.processedIds.length > 100) staticData.processedIds = staticData.processedIds.slice(-100);

let text = '';
let messageType = 'text';
let replyRef = null;
let replyContext = null;

const transcription = $input.first().json.text;
if (transcription && msg.voice) {
  text = transcription;
  messageType = 'voice';
} else if (msg.text) {
  text = msg.text;
  messageType = 'text';
} else if (msg.caption) {
  text = msg.caption;
  messageType = 'photo';
}

if (msg.reply_to_message) {
  const replyMsg = msg.reply_to_message;
  const replyText = replyMsg.text || replyMsg.caption || '';
  const replyMessageId = replyMsg.message_id;
  const ghMatch = replyText.match(/GitHub #(\d+) \(([\w-]+\/[\w-]+)\)/);
  if (ghMatch) replyRef = 'github:' + ghMatch[2] + '#' + ghMatch[1];
  if (!replyRef) {
    const memoMatch = replyText.match(/memos\/([\w-]+)/);
    if (memoMatch) replyRef = 'memo:' + memoMatch[1];
  }
  const projectMatch = replyText.match(/\u{1F4C1} ([\w-]+)/u);
  replyContext = {
    ref: replyRef,
    project: projectMatch ? projectMatch[1] : null,
    replyText: replyText.substring(0, 500),
    replyMessageId: replyMessageId,
    isFromBot: replyMsg.from?.is_bot === true,
  };
}

// Store in chat history
if (!staticData.chatHistory) staticData.chatHistory = [];
staticData.chatHistory.push({ role: 'user', text: text.substring(0, 300), ts: Date.now() });
if (staticData.chatHistory.length > 40) staticData.chatHistory = staticData.chatHistory.slice(-40);

const history = staticData.chatHistory.slice(-20).map(h => `[${h.role === 'user' ? 'You' : 'VoiceBrain'}] ${h.text}`).join('\n');

return [{
  json: {
    chatId, messageId, text, messageType, replyRef, replyContext,
    username: msg.from?.username || msg.from?.first_name || 'unknown',
    chatHistory: history,
  }
}];

const trigger = $('Message Trigger').first().json;
const cb = trigger.callback_query;
const data = cb.data.replace('vb:', '');
const chatId = cb.message.chat.id;

const staticData = $getWorkflowStaticData('global');
if (!staticData.chatHistory) staticData.chatHistory = [];
staticData.chatHistory.push({ role: 'user', text: `[Selected: ${data}]`, ts: Date.now() });
if (staticData.chatHistory.length > 40) staticData.chatHistory = staticData.chatHistory.slice(-40);
const history = staticData.chatHistory.slice(-20).map(h => `[${h.role === 'user' ? 'You' : 'VoiceBrain'}] ${h.text}`).join('\n');

return [{
  json: {
    chatId,
    text: `User selected: ${data}`,
    messageType: 'callback',
    chatHistory: history,
    replyContext: null,
    callbackQueryId: cb.id,
  }
}];

const msg=$('Message Trigger').first().json.message;
const chatId=msg.chat.id,txt=(msg.text||'').trim(),cmd=txt.split(' ')[0].toLowerCase(),args=txt.substring(cmd.length).trim();
const staticData=$getWorkflowStaticData('global');
let reply='';
if(cmd==='/start'){
  staticData.chatHistory=[];
  reply='\u{1F9E0} <b>VoiceBrain v2</b>\n\nI\'m your personal AI assistant. Send me voice notes, text, or photos and I\'ll handle them intelligently.\n\nCommands:\n/help - What I can do\n/tasks - Open tasks\n/search &lt;term&gt; - Search notes';
} else if(cmd==='/help'){
  reply='\u{1F4AC} <b>What I can do:</b>\n\n\u{1F4DD} Save notes, ideas, tasks\n\u{1F6D2} Add to shopping list\n\u{1F41D} Create GitHub issues\n\u{1F50D} Search your notes\n\u{1F310} Search the web\n\u270D\uFE0F Write emails in your style\n\u{1F504} Edit existing notes\n\n<i>Just talk to me naturally!</i>';
} else if(cmd==='/tasks'){
  reply='Fetching tasks... (use natural language instead, e.g. "show my open tasks")';
} else if(cmd==='/search'){
  if(!args) reply='Usage: /search &lt;term&gt;';
  else reply=`Searching... (use natural language instead, e.g. "search notes about ${args}")`;
} else {
  reply='Unknown command. Try /help';
}
return [{json:{chatId,text:reply}}];

try {
const args = typeof query === 'string' ? JSON.parse(query) : query;
if (!args.title) {
  const rawText = typeof query === 'string' ? query : JSON.stringify(query);
  args.title = rawText.substring(0, 80);
  args.body = rawText;
  args.tags = [];
}
const url = $env.MEMOS_URL || 'http://memos:5230';
const token = $env.MEMOS_TOKEN;
const tags = (args.tags || []).map(t => '#' + t.replace(/^#/, '')).join(' ');
const content = `${args.title}\n\n${args.body}\n\n${tags}`.trim();
const memo = await this.helpers.httpRequest({
  method: 'POST',
  url: `${url}/api/v1/memos`,
  headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
  body: JSON.stringify({ content, visibility: 'PRIVATE' }),
  json: true,
});
const uid = memo.name?.replace('memos/', '') || 'unknown';
return `Memo created: https://voicebrain.madridrollers.es/memos/${uid}`;
} catch(e) { return `Error creating memo: ${e.message}`; }

try {
let args = typeof query === 'string' ? JSON.parse(query) : query;
if (!args || !args.items) {
  const rawText = typeof query === 'string' ? query : JSON.stringify(query);
  const itemNames = rawText.split(/[,;y&]|\band\b/i).map(s => s.trim()).filter(s => s.length > 0);
  args = { items: itemNames.map(name => ({ item: name, spec: '' })) };
}
const items = args.items;
if (!items || !Array.isArray(items) || items.length === 0) {
  return 'No items specified.';
}
const email = $env.BRING_EMAIL;
const password = $env.BRING_PASSWORD;
if (!email || !password) return 'Bring! not configured.';
const BRING_API_KEY = '***REDACTED_BRING_CLIENT_KEY***';
const bringHeaders = { 'X-BRING-API-KEY': BRING_API_KEY, 'X-BRING-CLIENT': 'android', 'X-BRING-APPLICATION': 'bring' };
const loginResp = await this.helpers.httpRequest({
  method: 'POST', url: 'https://api.getbring.com/rest/v2/bringauth',
  headers: { ...bringHeaders, 'Content-Type': 'application/x-www-form-urlencoded' },
  body: `email=${encodeURIComponent(email)}&password=${encodeURIComponent(password)}`,
  json: true,
});
const token = loginResp.access_token;
const uuid = loginResp.uuid;
if (!token || !uuid) return 'Bring! login failed.';
const authHeaders = { 'Authorization': `Bearer ${token}`, ...bringHeaders };
const listsResp = await this.helpers.httpRequest({
  method: 'GET', url: `https://api.getbring.com/rest/v2/bringusers/${uuid}/lists`,
  headers: authHeaders, json: true,
});
const listId = listsResp.lists?.[0]?.listUuid;
if (!listId) return 'No shopping list found in Bring!';
const added = [];
for (const it of items) {
  const name = (it.item || it.name || it).toString().trim();
  if (!name) continue;
  const spec = (it.spec || it.detail || '').toString().trim();
  await this.helpers.httpRequest({
    method: 'PUT',
    url: `https://api.getbring.com/rest/v2/bringlists/${listId}`,
    headers: { ...authHeaders, 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `purchase=${encodeURIComponent(name)}&specification=${encodeURIComponent(spec)}`,
  });
  added.push(spec ? `${name} (${spec})` : name);
}
return `Added to shopping list: ${added.join(', ')}`;
} catch(e) { return `Bring! error: ${e.message}`; }

try {
const args = typeof query === 'string' ? JSON.parse(query) : query;
if (!args || !args.project) {
  return 'Please provide project and title as JSON.';
}
const pat = $env.GITHUB_PAT;
if (!pat) return 'GitHub not configured.';
const headers = { 'Authorization': `Bearer ${pat}`, 'Accept': 'application/vnd.github+json', 'X-GitHub-Api-Version': '2022-11-28' };
const repos = await this.helpers.httpRequest({
  method: 'GET', url: 'https://api.github.com/user/repos?per_page=100&sort=updated&type=all',
  headers, json: true,
});
const repoList = repos.filter(r => !r.archived).map(r => ({ name: r.name, full: r.full_name }));
const p = (args.project || '').toLowerCase();
let repo = repoList.find(r => r.name.toLowerCase() === p)?.full;
if (!repo) repo = repoList.find(r => r.name.toLowerCase().includes(p) || p.includes(r.name.toLowerCase()))?.full;
if (!repo) {
  const parts = p.split('-');
  repo = repoList.find(r => parts.some(pt => pt.length > 2 && r.name.toLowerCase().includes(pt)))?.full;
}
if (!repo) return `No matching repo for "${args.project}". Available: ${repoList.map(r => r.name).join(', ')}`;
const issue = await this.helpers.httpRequest({
  method: 'POST', url: `https://api.github.com/repos/${repo}/issues`,
  headers: { ...headers, 'Content-Type': 'application/json' },
  body: JSON.stringify({ title: args.title, body: `${args.body || ''}\n\n---\n_Created via VoiceBrain_` }),
  json: true,
});
return `GitHub Issue #${issue.number} created in ${repo}: ${issue.html_url}`;
} catch(e) { return `GitHub error: ${e.message}`; }

try {
const searchTerm = typeof query === 'string' ? query : (query?.query || '');
if (!searchTerm) return 'Please specify a search term.';
const url = $env.MEMOS_URL || 'http://memos:5230';
const token = $env.MEMOS_TOKEN;
const response = await this.helpers.httpRequest({
  method: 'GET', url: `${url}/api/v1/memos`,
  qs: { pageSize: 50 },
  headers: { 'Authorization': `Bearer ${token}` }, json: true,
});
const memos = (response.memos || []).filter(m => 
  (m.content || '').toLowerCase().includes(searchTerm.toLowerCase())
);
if (memos.length === 0) return `No memos found containing "${searchTerm}".`;
const results = memos.slice(0, 5).map(m => {
  const uid = m.name?.replace('memos/', '') || '?';
  const preview = (m.content || '').substring(0, 150).replace(/\n/g, ' ');
  return `- ${preview}... (https://voicebrain.madridrollers.es/memos/${uid})`;
});
return `Found ${memos.length} memo(s):\n${results.join('\n')}`;
} catch(e) { return `Search error: ${e.message}`; }

try {
const searchTerm = typeof query === 'string' ? query : (query?.query || '');
if (!searchTerm) return 'Please specify a search term.';
const apiKey = $env.BRAVE_SEARCH_KEY;
if (!apiKey) return 'Web search not configured (missing BRAVE_SEARCH_KEY).';
const response = await this.helpers.httpRequest({
  method: 'GET', url: 'https://api.search.brave.com/res/v1/web/search',
  qs: { q: searchTerm, count: 5 },
  headers: { 'Accept': 'application/json', 'Accept-Encoding': 'gzip', 'X-Subscription-Token': apiKey },
  json: true,
});
const results = (response.web?.results || []).slice(0, 5).map(r => 
  `- ${r.title}: ${r.description || ''} (${r.url})`
);
return results.length ? `Web results for "${searchTerm}":\n${results.join('\n')}` : `No web results for "${searchTerm}".`;
} catch(e) { return `Web search error: ${e.message}`; }

try {
const args = typeof query === 'string' ? JSON.parse(query) : query;
if (!args || !args.memo_id) {
  return 'Please specify a memo_id and mode (append, replace, mark_done, replace_tag).';
}
const url = $env.MEMOS_URL || 'http://memos:5230';
const token = $env.MEMOS_TOKEN;
const authH = { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' };
const memoUrl = `${url}/api/v1/memos/${args.memo_id}`;
const mode = (args.mode || 'append').toLowerCase();

const current = await this.helpers.httpRequest({
  method: 'GET', url: memoUrl,
  headers: { 'Authorization': `Bearer ${token}` }, json: true,
});
if (!current || !current.content) return `Memo ${args.memo_id} not found or empty.`;
let content = current.content;

if (mode === 'mark_done') {
  if (!content.includes('#open')) {
    return `Memo ${args.memo_id} does not have #open tag. Current tags: ${(content.match(/#\w+/g) || []).join(', ')}`;
  }
  content = content.replace(/#open/g, '#done');
} else if (mode === 'replace_tag') {
  const oldTag = args.old_tag || args.oldTag;
  const newTag = args.new_tag || args.newTag;
  if (!oldTag || !newTag) return 'replace_tag mode requires old_tag and new_tag.';
  content = content.replace(new RegExp(oldTag.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'), newTag);
} else if (mode === 'replace') {
  if (!args.new_content) return 'replace mode requires new_content.';
  content = args.new_content;
} else {
  if (!args.new_content) return 'append mode requires new_content.';
  content = content + '\n\n---\n' + args.new_content;
}

await this.helpers.httpRequest({
  method: 'PATCH', url: memoUrl,
  headers: authH,
  body: JSON.stringify({ content }),
  json: true,
});
return `Memo updated (${mode}). View: https://voicebrain.madridrollers.es/memos/${args.memo_id}`;
} catch(e) { return `Update error: ${e.message}`; }

try {
const project = typeof query === 'string' && query.trim() ? query.trim() : null;
const url = $env.MEMOS_URL || 'http://memos:5230';
const token = $env.MEMOS_TOKEN;
const response = await this.helpers.httpRequest({
  method: 'GET', url: `${url}/api/v1/memos`,
  qs: { pageSize: 50, filter: 'content.contains("#task") && content.contains("#open")' },
  headers: { 'Authorization': `Bearer ${token}` }, json: true,
});
let memos = response.memos || [];
if (project) {
  const p = project.toLowerCase();
  memos = memos.filter(m => (m.content || '').toLowerCase().includes(p));
}
const tasks = memos.map(m => {
  const title = (m.content || '').split('\n')[0].substring(0, 80);
  return `\u2022 ${title}`;
});
return tasks.length ? `${tasks.length} open tasks:\n${tasks.join('\n')}` : 'No open tasks found.';
} catch(e) { return `Tasks error: ${e.message}`; }

try {
const args = typeof query === 'string' ? JSON.parse(query) : query;
if (!args || !args.question || !args.options) {
  return 'Please provide a question and options for the buttons.';
}
const chatId = $('Parse Input').first()?.json?.chatId || $getWorkflowStaticData('global').lastChatId;
const staticData = $getWorkflowStaticData('global');
const botToken = staticData._botToken;
if (!botToken) return 'Bot token not available for sending buttons.';
const keyboard = {
  inline_keyboard: args.options.map(o => [{ text: o.label, callback_data: `vb:${o.id}` }]),
};
await this.helpers.httpRequest({
  method: 'POST', url: `https://api.telegram.org/bot${botToken}/sendMessage`,
  body: JSON.stringify({ chat_id: chatId, text: args.question, reply_markup: keyboard, parse_mode: 'HTML' }),
  headers: { 'Content-Type': 'application/json' }, json: true,
});
return `Question sent: "${args.question}" with ${args.options.length} options. Wait for reply.`;
} catch(e) { return `Button error: ${e.message}`; }

const agentOutput = $json.output || $json.text || '';
const parseInput = $('Parse Input');
let chatId;
try { chatId = parseInput.first()?.json?.chatId; } catch(e) {}
if (!chatId) {
  try { chatId = $('Parse Callback').first()?.json?.chatId; } catch(e) {}
}
if (!chatId) {
  try { chatId = $('Answer Callback').first()?.json?.chatId; } catch(e) {}
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.chatHistory) staticData.chatHistory = [];
staticData.chatHistory.push({ role: 'assistant', text: agentOutput.substring(0, 300), ts: Date.now() });
if (staticData.chatHistory.length > 40) staticData.chatHistory = staticData.chatHistory.slice(-40);
if (chatId) staticData.lastChatId = chatId;

return [{ json: { chatId, text: agentOutput } }];
